import type { DiaryPreset } from "@/lib/diary-presets";
import type { FieldCadence, PatientSex } from "@/lib/types";

// Diary template library (PRD §5.9.1). Curated bundles of tracked fields that
// encode what people commonly track for a protocol or goal. A template is just
// metadata + existing-style DiaryPreset entries; confirming one creates ordinary
// tracked_fields rows. NOTHING here is generated by an LLM — this is a
// human-reviewed catalogue with the same discipline as the drug-interaction
// table (architecture rule #9 in spirit). Framing is strictly non-directive
// (PRD §6.1): these are things people find interesting to see over time, never
// safety monitoring, never "you should track X".
//
// Field notation maps onto the existing FIELD_TYPES — no new field kinds:
//   number · scale_1_10 · boolean · freetext · category · multiselect.

export type DiaryTemplate = {
  id: string;
  name: string;
  kind: "medication" | "goal" | "care";
  /** one plain-language sentence — what people commonly track and why it's
   *  interesting over time. Never directive. */
  description: string;
  /** orders / filters visibility only; never auto-selects anything */
  audience?: { sex?: PatientSex; minAge?: number };
  /** lowercased generic drug names that surface this on medication add */
  matchTerms?: string[];
  coreFields: DiaryPreset[]; // default-checked, ≤ 8
  optionalFields: DiaryPreset[]; // default-unchecked
  periodicFields?: DiaryPreset[]; // labs/measurements — "log when you have a result"
};

// ── Terse field builders (group is a display header only; not stored) ────────
const num = (group: string, name: string, unit?: string): DiaryPreset => ({
  name,
  field_type: "number",
  group,
  ...(unit ? { unit } : {}),
});
const scale = (group: string, name: string): DiaryPreset => ({
  name,
  field_type: "scale_1_10",
  group,
});
const yn = (group: string, name: string): DiaryPreset => ({
  name,
  field_type: "boolean",
  group,
});
const text = (group: string, name: string): DiaryPreset => ({
  name,
  field_type: "freetext",
  group,
});
const one = (group: string, name: string, options: string[]): DiaryPreset => ({
  name,
  field_type: "category",
  group,
  category_options: options,
});
const many = (group: string, name: string, options: string[]): DiaryPreset => ({
  name,
  field_type: "multiselect",
  group,
  category_options: options,
});

