// ── Lookups & filtering ──────────────────────────────────────────────────────

/** Medication templates whose matchTerms overlap the drug's canonical name.
 *  Substring either way so "testosterone" matches "testosterone cypionate". */
export function templatesForDrug(
  canonicalName: string | null | undefined
): DiaryTemplate[] {
  const c = (canonicalName ?? "").trim().toLowerCase();
  if (!c) return [];
  return DIARY_TEMPLATES.filter(
    (t) =>
      t.kind === "medication" &&
      (t.matchTerms ?? []).some((term) => {
        const m = term.toLowerCase();
        return c.includes(m) || m.includes(c);
      })
  );
}

export function templateById(id: string): DiaryTemplate | undefined {
  return DIARY_TEMPLATES.find((t) => t.id === id);
}

/** Whether a template should be visible for a patient's demographics. A known
 *  mismatched sex hides it; unknown sex shows everything (the user can still
 *  browse it). Age only hides when both the gate and the age are known. */
export function audienceMatches(
  t: DiaryTemplate,
  opts: { sex?: PatientSex | null; age?: number | null }
): boolean {
  const a = t.audience;
  if (!a) return true;
  if (a.sex && opts.sex && a.sex !== opts.sex) return false;
  if (a.minAge != null && opts.age != null && opts.age < a.minAge) return false;
  return true;
}

/** Templates for the browsable gallery, audience-filtered. */
export function galleryTemplates(opts: {
  sex?: PatientSex | null;
  age?: number | null;
}): DiaryTemplate[] {
  return DIARY_TEMPLATES.filter((t) => audienceMatches(t, opts));
}

/** Whole-years age from an ISO date-of-birth, relative to `now` (ms). */
export function ageFromDob(
  dob: string | null | undefined,
  now: number
): number | null {
  if (!dob) return null;
  const born = new Date(dob).getTime();
  if (!Number.isFinite(born)) return null;
  return Math.floor((now - born) / (365.25 * 86_400_000));
}

export type TemplateBucket = "core" | "optional" | "periodic";

export type TemplateFieldRow = {
  preset: DiaryPreset;
  bucket: TemplateBucket;
  cadence: FieldCadence;
  defaultChecked: boolean;
};

/** Flatten a template into rows for the confirm screen / apply action: core is
 *  checked + daily, optional is unchecked + daily, periodic is unchecked +
 *  periodic (kept off the daily form). */
export function templateFieldRows(t: DiaryTemplate): TemplateFieldRow[] {
  const rows: TemplateFieldRow[] = [];
  for (const preset of t.coreFields) {
    rows.push({ preset, bucket: "core", cadence: "daily", defaultChecked: true });
  }
  for (const preset of t.optionalFields) {
    rows.push({ preset, bucket: "optional", cadence: "daily", defaultChecked: false });
  }
  for (const preset of t.periodicFields ?? []) {
    rows.push({ preset, bucket: "periodic", cadence: "periodic", defaultChecked: false });
  }
  return rows;
}
